import json

graph_data = json.loads(content)

def sanitize(obj):
    if isinstance(obj, str):
        result = []
        for ch in obj:
            cp = ord(ch)
            if 0xD800 <= cp <= 0xDFFF:
                result.append('?')
            else:
                result.append(ch)
        return ''.join(result)
    elif isinstance(obj, dict):
        return {k: sanitize(v) for k, v in obj.items()}
    elif isinstance(obj, list):
        return [sanitize(v) for v in obj]
    else:
        return obj

clean_data = sanitize(graph_data)

